# Check available variables and understand the data
available_vars = [k for k in locals().keys() if k.startswith('var_')]
print("__RESULT__:")
import json
result = {
    'available_keys': available_vars,
    'key_info': {}
}
for key in available_vars:
    val = locals()[key]
    if isinstance(val, list) and val:
        result['key_info'][key] = {
            'type': 'list',
            'length': len(val),
            'first_item': val[0]
        }
    elif isinstance(val, str):
        result['key_info'][key] = {
            'type': 'str',
            'preview': val[:200]
        }
    else:
        result['key_info'][key] = {
            'type': str(type(val))
        }
print(json.dumps(result))

